import{bV as s,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"自动组织分析","description":"","frontmatter":{},"headers":[],"relativePath":"prompts/自动组织分析.md","filePath":"prompts/自动组织分析.md","lastUpdated":1777604859000}'),t={name:"prompts/自动组织分析.md"};function e(i,n,o,c,u,q){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="自动组织分析" tabindex="-1">自动组织分析 <a class="header-anchor" href="#自动组织分析" aria-label="Permalink to &quot;自动组织分析&quot;">​</a></h1><blockquote><p>模板键: <code>AUTO_ORGANIZATION_ANALYSIS</code> 分类: 自动组织引入 描述: 分析新生成的大纲，判断是否需要引入新组织 参数: [&quot;title&quot;, &quot;genre&quot;, &quot;theme&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;existing_organizations&quot;, &quot;existing_characters&quot;, &quot;all_chapters_brief&quot;, &quot;start_chapter&quot;, &quot;chapter_count&quot;, &quot;plot_stage&quot;, &quot;story_direction&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的小说世界构建顾问，擅长预测剧情发展对组织/势力的需求。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【分析任务】</span></span>
<span class="line"><span>预测在接下来的{chapter_count}章续写中，根据剧情发展方向和阶段，是否需要引入新的组织或势力。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【重要说明】</span></span>
<span class="line"><span>这是预测性分析，而非基于已生成内容的事后分析。</span></span>
<span class="line"><span>组织包括：帮派、门派、公司、政府机构、神秘组织、家族等。</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;project priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【世界观】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>&lt;/project&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;context priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【已有组织】</span></span>
<span class="line"><span>{existing_organizations}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【已有角色】</span></span>
<span class="line"><span>{existing_characters}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【已有章节概览】</span></span>
<span class="line"><span>{all_chapters_brief}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【续写计划】</span></span>
<span class="line"><span>- 起始章节：第{start_chapter}章</span></span>
<span class="line"><span>- 续写数量：{chapter_count}章</span></span>
<span class="line"><span>- 剧情阶段：{plot_stage}</span></span>
<span class="line"><span>- 发展方向：{story_direction}</span></span>
<span class="line"><span>&lt;/context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;analysis_framework priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【预测分析维度】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**1. 世界观扩展需求**</span></span>
<span class="line"><span>根据发展方向，是否需要新的势力或组织来丰富世界观？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**2. 冲突升级需求**</span></span>
<span class="line"><span>剧情是否需要新的对立势力、竞争组织或神秘集团？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**3. 角色归属需求**</span></span>
<span class="line"><span>现有角色是否需要加入或对抗某个新组织？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**4. 剧情推动需求**</span></span>
<span class="line"><span>新组织能否成为推动剧情的关键力量？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**5. 引入时机**</span></span>
<span class="line"><span>新组织应该在哪个章节出现最合适？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【预测依据】</span></span>
<span class="line"><span>- 剧情阶段的典型组织需求（如：高潮阶段可能需要强大的敌对势力）</span></span>
<span class="line"><span>- 故事发展方向的逻辑需要（如：进入新地点需要当地势力）</span></span>
<span class="line"><span>- 世界观完整性需要（如：权力格局需要多方势力）</span></span>
<span class="line"><span>- 角色成长需要（如：主角需要加入或创建组织）</span></span>
<span class="line"><span>&lt;/analysis_framework&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;naming_guidelines priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【命名要求】</span></span>
<span class="line"><span>如果【已有组织】中存在组织，建议的新组织命名风格必须与已有组织保持一致。</span></span>
<span class="line"><span>参考已有组织的名称规律（用词习惯、字数、文化风格），生成符合同一世界观的建议名称。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【各类型组织命名风格】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**现代都市**：公司用全称/简称（盛华集团、锐思科技）、机构用正式名称（市公安局、第一人民医院）</span></span>
<span class="line"><span>**玄幻仙侠**：用意境词+门派词（天剑宗、幽冥殿、星辰阁、万兽山庄）</span></span>
<span class="line"><span>**科幻**：用编号/代号/功能名（第七舰队、量子研究所、新星联邦）</span></span>
<span class="line"><span>**历史古代**：用朝代+职能（锦衣卫、漕帮、翰林院）</span></span>
<span class="line"><span>**奇幻魔法**：用象征词+组织词（银月骑士团、暗影议会、龙语学院）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名原则】</span></span>
<span class="line"><span>- 参考已有组织的命名风格，保持高度一致</span></span>
<span class="line"><span>- 名称要有文化代入感，不要用现代词汇套古代背景</span></span>
<span class="line"><span>- 组织名称长度2-6个字为佳</span></span>
<span class="line"><span>- 如果已有组织名称都是&quot;XX宗/XX阁/XX殿&quot;格式，建议名称也用相同格式</span></span>
<span class="line"><span>- 如果已有组织名称都是现代公司名格式，建议名称也用相同格式</span></span>
<span class="line"><span>&lt;/naming_guidelines&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回纯JSON对象（两种情况之一）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**情况A：需要新组织**</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>&quot;needs_new_organizations&quot;: true,</span></span>
<span class="line"><span>&quot;reason&quot;: &quot;预测分析原因（150-200字），说明为什么即将的剧情需要新组织&quot;,</span></span>
<span class="line"><span>&quot;organization_count&quot;: 1,</span></span>
<span class="line"><span>&quot;organization_specifications&quot;: [</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;name&quot;: &quot;建议的组织名称（必须符合已有组织的命名风格和规律）&quot;,</span></span>
<span class="line"><span>  &quot;organization_description&quot;: &quot;组织在剧情中的定位和作用（100-150字）&quot;,</span></span>
<span class="line"><span>  &quot;organization_type&quot;: &quot;帮派/门派/公司/政府/家族/神秘组织等&quot;,</span></span>
<span class="line"><span>  &quot;importance&quot;: &quot;high/medium/low&quot;,</span></span>
<span class="line"><span>  &quot;appearance_chapter&quot;: {start_chapter},</span></span>
<span class="line"><span>  &quot;power_level&quot;: 70,</span></span>
<span class="line"><span>  &quot;plot_function&quot;: &quot;在剧情中的具体功能&quot;,</span></span>
<span class="line"><span>  &quot;location&quot;: &quot;组织所在地或活动区域&quot;,</span></span>
<span class="line"><span>  &quot;motto&quot;: &quot;组织口号或宗旨（可选）&quot;,</span></span>
<span class="line"><span>  &quot;naming_rationale&quot;: &quot;命名理由：说明为什么这个名字符合已有组织的命名风格&quot;,</span></span>
<span class="line"><span>  &quot;initial_members&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;character_name&quot;: &quot;现有角色名（必须精确匹配已有角色，如需加入）&quot;,</span></span>
<span class="line"><span>      &quot;position&quot;: &quot;职位&quot;,</span></span>
<span class="line"><span>      &quot;reason&quot;: &quot;为什么加入&quot;</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;relationship_suggestions&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;target_organization&quot;: &quot;已有组织名（必须精确匹配已有组织）&quot;,</span></span>
<span class="line"><span>      &quot;relationship_type&quot;: &quot;建议的关系类型（盟友/敌对/竞争/合作等）&quot;,</span></span>
<span class="line"><span>      &quot;reason&quot;: &quot;为什么建立这种关系&quot;</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>]</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**情况B：不需要新组织**</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>&quot;needs_new_organizations&quot;: false,</span></span>
<span class="line"><span>&quot;reason&quot;: &quot;现有组织足以支撑即将的剧情发展，说明理由&quot;</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 这是预测性分析，面向未来剧情</span></span>
<span class="line"><span>✅ 考虑世界观的丰富性和完整性</span></span>
<span class="line"><span>✅ 确保引入必要性，不为引入而引入</span></span>
<span class="line"><span>✅ 优先考虑组织的长期作用</span></span>
<span class="line"><span>✅ 组织应该是推动剧情的关键力量</span></span>
<span class="line"><span>✅ character_name必须精确匹配【已有角色】</span></span>
<span class="line"><span>✅ target_organization必须精确匹配【已有组织】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【命名约束】</span></span>
<span class="line"><span>✅ 如果已有组织存在，建议的组织名称风格必须与已有组织一致</span></span>
<span class="line"><span>✅ 组织名称必须符合世界观文化背景</span></span>
<span class="line"><span>✅ 参考已有组织的命名规律（用词习惯、字数、文化风格）</span></span>
<span class="line"><span>✅ 提供 naming_rationale 说明命名理由</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出markdown标记</span></span>
<span class="line"><span>❌ 基于已生成内容做事后分析</span></span>
<span class="line"><span>❌ 为了引入组织而强行引入</span></span>
<span class="line"><span>❌ 设计一次性功能组织</span></span>
<span class="line"><span>❌ 创建与现有组织功能重复的组织</span></span>
<span class="line"><span>❌ 忽略已有组织命名风格，随意编造建议名称</span></span>
<span class="line"><span>❌ 古代背景使用现代组织名（如&quot;XX科技&quot;&quot;XX集团&quot;）</span></span>
<span class="line"><span>❌ 现代背景使用古代门派名（如&quot;XX宗&quot;&quot;XX阁&quot;）</span></span>
<span class="line"><span>❌ 使用与世界观不匹配的词汇命名</span></span>
<span class="line"><span>❌ 引用不存在的角色或组织</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const g=s(t,[["render",e]]);export{_ as __pageData,g as default};
